                <div class="settings-toast @(_toastIsError ? "toast-error" : "toast-success")">
                    <span>@_toastMessage</span>
                    <button class="toast-dismiss" @onclick="DismissToast">✕</button>
                </div>
            }

            @switch (ActiveSection)
            {
                case "profile":
                    @RenderProfileSection()
                    break;
                case "notifications":
                    @RenderNotificationsSection()
                    break;
                case "security":
                    @RenderSecuritySection()
                    break;
                case "appearance":
                    @RenderAppearanceSection()
                    break;
            }
        }
    </div>
</div>

@* ───── Profile Section ───── *@
@{ RenderFragment RenderProfileSection() =>
    @<section class="settings-section">
        <h2 class="section-title">Profile</h2>
        <p class="section-description">Manage your personal information and public profile.</p>

        <div class="form-group avatar-group">
            <label>Avatar</label>
            <div class="avatar-preview">
                @if (!string.IsNullOrWhiteSpace(_profileDisplayName))
                {
                    <img src="@_profileAvatarUrl" alt="Avatar" class="avatar-img" />
                }
                else
                {
                    <div class="avatar-placeholder">?</div>
                }
            </div>
            <span class="avatar-url-display text-muted">@_profileAvatarUrl</span>
        </div>

        <div class="form-group">
            <label for="displayName">Display Name</label>
            <input id="displayName" type="text" class="form-control" @bind="_profileDisplayName" />
        </div>

        <div class="form-group">
            <label for="email">Email</label>
            <input id="email" type="email" class="form-control" @bind="_profileEmail" />
        </div>

        <div class="form-group">
            <label for="bio">Bio</label>
            <textarea id="bio" class="form-control" rows="4" @bind="_profileBio"></textarea>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveProfile" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Changes
            </button>
            <button class="btn btn-outline-secondary" @onclick="DiscardProfileChanges" disabled="@_saving">
                Discard Changes
            </button>
        </div>
    </section>;
}

@* ───── Notifications Section ───── *@
@{ RenderFragment RenderNotificationsSection() =>
    @<section class="settings-section">
        <h2 class="section-title">Notifications</h2>
        <p class="section-description">Control how and when you receive notifications.</p>

        <div class="toggle-group">
            <div class="toggle-row">
                <div>
                    <strong>Email Notifications</strong>
                    <p class="text-muted mb-0">Receive notifications via email.</p>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_notifEmail" />
                    <span class="toggle-slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <div>
                    <strong>Push Notifications</strong>
                    <p class="text-muted mb-0">Receive push notifications in your browser.</p>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_notifPush" />
                    <span class="toggle-slider"></span>
                </label>
            </div>

            <div class="toggle-row">
                <div>
                    <strong>Weekly Digest</strong>
                    <p class="text-muted mb-0">Get a weekly summary of activity.</p>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_notifWeeklyDigest" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        <div class="form-group">
            <h4>Muted Channels</h4>
            <p class="text-muted">Uncheck channels you want to mute.</p>
            <div class="channel-list">
                @foreach (var channel in _allChannels)
                {
                    var isMuted = _mutedChannels.Contains(channel);
                    <label class="channel-item">
                        <input type="checkbox" checked="@(!isMuted)"
                               @onchange="(e) => ToggleChannelMute(channel, e)" />
                        <span>@channel</span>
                    </label>
                }
            </div>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveNotifications" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save Preferences
            </button>
        </div>
    </section>;
}

@* ───── Security Section ───── *@
@{ RenderFragment RenderSecuritySection() =>
    @<section class="settings-section">
        <h2 class="section-title">Security</h2>
        <p class="section-description">Manage your password, two-factor authentication, and active sessions.</p>

        <div class="card expandable-panel">
            <div class="card-header expandable-header" @onclick="TogglePasswordPanel">
                <strong>Change Password</strong>
                <span class="expand-icon">@(_passwordPanelOpen ? "▲" : "▼")</span>
            </div>
            @if (_passwordPanelOpen)
            {
                <div class="card-body">
                    <div class="form-group">
                        <label for="currentPassword">Current Password</label>
                        <input id="currentPassword" type="password" class="form-control" @bind="_currentPassword" />
                    </div>
                    <div class="form-group">
                        <label for="newPassword">New Password</label>
                        <input id="newPassword" type="password" class="form-control" @bind="_newPassword" />
                    </div>
                    <div class="form-group">
                        <label for="confirmPassword">Confirm Password</label>
                        <input id="confirmPassword" type="password" class="form-control" @bind="_confirmPassword" />
                    </div>
                    @if (!string.IsNullOrEmpty(_passwordError))
                    {
                        <div class="alert alert-danger">@_passwordError</div>
                    }
                    <button class="btn btn-warning" @onclick="ChangePassword" disabled="@_saving">
                        @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                        Update Password
                    </button>
                </div>
            }
        </div>

        <div class="toggle-group mt-3">
            <div class="toggle-row">
                <div>
                    <strong>Two-Factor Authentication</strong>
                    <p class="text-muted mb-0">
                        Status:
                        <span class="badge @(_twoFactorEnabled ? "bg-success" : "bg-secondary")">
                            @(_twoFactorEnabled ? "Enabled" : "Disabled")
                        </span>
                    </p>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_twoFactorEnabled" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        @if (_securityLastPasswordChange.HasValue)
        {
            <p class="text-muted mt-2">
                Last password change: @_securityLastPasswordChange.Value.ToString("MMMM dd, yyyy")
            </p>
        }

        <h4 class="mt-4">Active Sessions</h4>
        <div class="table-responsive">
            <table class="table table-striped">
                <thead>
                    <tr>
                        <th>Device</th>
                        <th>Location</th>
                        <th>Last Active</th>
                        <th></th>
                    </tr>
                </thead>
                <tbody>
                    @if (_sessions is not null)
                    {
                        @foreach (var session in _sessions)
                        {
                            <tr>
                                <td>@session.Device</td>
                                <td>@session.Location</td>
                                <td>@session.LastActive.ToString("g")</td>
                                <td>
                                    @if (session != _sessions.FirstOrDefault())
                                    {
                                        <button class="btn btn-sm btn-outline-danger"
                                                @onclick="() => PromptRevokeSession(session)">
                                            Revoke
                                        </button>
                                    }
                                    else
                                    {
                                        <span class="badge bg-info">Current</span>
                                    }
                                </td>
                            </tr>
                        }
                    }
                </tbody>
            </table>
        </div>

        @if (_sessionToRevoke is not null)
        {
            <div class="modal-backdrop-custom" @onclick="CancelRevoke">
                <div class="confirm-dialog" @onclick:stopPropagation>
                    <h5>Revoke Session</h5>
                    <p>Are you sure you want to revoke the session on <strong>@_sessionToRevoke.Device</strong> in <strong>@_sessionToRevoke.Location</strong>?</p>
                    <div class="button-row">
                        <button class="btn btn-danger" @onclick="ConfirmRevokeSession" disabled="@_saving">
                            @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                            Revoke
                        </button>
                        <button class="btn btn-outline-secondary" @onclick="CancelRevoke" disabled="@_saving">Cancel</button>
                    </div>
                </div>
            </div>
        }
    </section>;
}

@* ───── Appearance Section ───── *@
@{ RenderFragment RenderAppearanceSection() =>
    @<section class="settings-section">
        <h2 class="section-title">Appearance</h2>
        <p class="section-description">Customize the look and feel of the application.</p>

        <div class="form-group">
            <label><strong>Theme</strong></label>
            <div class="radio-group">
                @foreach (var theme in new[] { "Light", "Dark", "System" })
                {
                    <label class="radio-item">
                        <input type="radio" name="theme" value="@theme"
                               checked="@(_appearanceTheme == theme)"
                               @onchange="() => { _appearanceTheme = theme; }" />
                        <span>@theme</span>
                    </label>
                }
            </div>
        </div>

        <div class="form-group">
            <label><strong>Font Size</strong></label>
            <div class="radio-group">
                @foreach (var size in new[] { "Small", "Medium", "Large" })
                {
                    <label class="radio-item">
                        <input type="radio" name="fontSize" value="@size"
                               checked="@(_appearanceFontSize == size)"
                               @onchange="() => { _appearanceFontSize = size; }" />
                        <span>@size</span>
                    </label>
                }
            </div>
        </div>

        <div class="form-group">
            <label for="language"><strong>Language</strong></label>
            <select id="language" class="form-select" @bind="_appearanceLanguage">
                <option value="en">English</option>
                <option value="es">Español</option>
                <option value="fr">Français</option>
                <option value="de">Deutsch</option>
                <option value="ja">日本語</option>
                <option value="zh">中文</option>
            </select>
        </div>

        <div class="toggle-group">
            <div class="toggle-row">
                <div>
                    <strong>Compact Mode</strong>
                    <p class="text-muted mb-0">Reduce spacing and padding throughout the UI.</p>
                </div>
                <label class="toggle-switch">
                    <input type="checkbox" @bind="_appearanceCompactMode" />
                    <span class="toggle-slider"></span>
                </label>
            </div>
        </div>

        <div class="form-group mt-3">
            <label><strong>Live Preview</strong></label>
            <div class="live-preview @GetPreviewClasses()">
                <div class="preview-header">Sample Header</div>
                <p class="preview-body">
                    This is a preview of your selected appearance settings.
                    The theme, font size, and compact mode are reflected here.
                </p>
                <button class="preview-button">Sample Button</button>
            </div>
        </div>

        <div class="button-row">
            <button class="btn btn-primary" @onclick="SaveAppearance" disabled="@_saving">
                @if (_saving) { <span class="spinner-border spinner-border-sm me-1"></span> }
                Save
            </button>
        </div>
    </section>;
}

@code {
    // ── Navigation ──
    private string ActiveSection { get; set; } = "profile";

    private readonly Dictionary<string, (string Label, string Icon)> _sections = new()
    {
        ["profile"] = ("Profile", "👤"),
        ["notifications"] = ("Notifications", "🔔"),
        ["security"] = ("Security", "🔒"),
        ["appearance"] = ("Appearance", "🎨")
    };

    // ── UI state ──
    private bool _loading = true;
    private bool _saving;
    private string? _toastMessage;
    private bool _toastIsError;
    private System.Threading.Timer? _toastTimer;

    // ── Profile fields ──
    private string _profileDisplayName = "";
    private string _profileEmail = "";
    private string _profileAvatarUrl = "";
    private string _profileBio = "";
    private UserProfile? _savedProfile;

    // ── Notification fields ──
    private bool _notifEmail;
    private bool _notifPush;
    private bool _notifWeeklyDigest;
    private List<string> _mutedChannels = new();
    private readonly List<string> _allChannels = new()
    {
        "general", "announcements", "engineering", "design", "marketing", "support", "random"
    };

    // ── Security fields ──
    private bool _passwordPanelOpen;
    private string _currentPassword = "";
    private string _newPassword = "";
    private string _confirmPassword = "";
    private string? _passwordError;
    private bool _twoFactorEnabled;
    private DateTime? _securityLastPasswordChange;
    private List<ActiveSession>? _sessions;
    private ActiveSession? _sessionToRevoke;

    // ── Appearance fields ──
    private string _appearanceTheme = "System";
    private string _appearanceFontSize = "Medium";
    private string _appearanceLanguage = "en";
    private bool _appearanceCompactMode;

    protected override async Task OnInitializedAsync()
    {
        await LoadAllSettingsAsync();
        _loading = false;
    }

    private async Task LoadAllSettingsAsync()
    {
        var profileTask = SettingsService.GetProfileAsync();
        var notifTask = SettingsService.GetNotificationPrefsAsync();
        var securityTask = SettingsService.GetSecuritySettingsAsync();
        var appearanceTask = SettingsService.GetAppearanceAsync();

        await Task.WhenAll(profileTask, notifTask, securityTask, appearanceTask);

        var profile = profileTask.Result;
        _savedProfile = profile;
        _profileDisplayName = profile.DisplayName;
        _profileEmail = profile.Email;
        _profileAvatarUrl = profile.AvatarUrl;
        _profileBio = profile.Bio;

        var notif = notifTask.Result;
        _notifEmail = notif.EmailNotifications;
        _notifPush = notif.PushNotifications;
        _notifWeeklyDigest = notif.WeeklyDigest;
        _mutedChannels = new List<string>(notif.MutedChannels);

        var security = securityTask.Result;
        _twoFactorEnabled = security.TwoFactorEnabled;
        _securityLastPasswordChange = security.LastPasswordChange;
        _sessions = security.Sessions;

        var appearance = appearanceTask.Result;
        _appearanceTheme = appearance.Theme;
        _appearanceFontSize = appearance.FontSize;
        _appearanceLanguage = appearance.Language;
        _appearanceCompactMode = appearance.CompactMode;
    }

    // ── Navigation ──
    private void SetActiveSection(string section) => ActiveSection = section;

    // ── Toast ──
    private void ShowToast(string message, bool isError = false)
    {
        _toastMessage = message;
        _toastIsError = isError;
        _toastTimer?.Dispose();
        _toastTimer = new System.Threading.Timer(_ =>
        {
            _toastMessage = null;
            InvokeAsync(StateHasChanged);
        }, null, 4000, Timeout.Infinite);
    }

    private void DismissToast()
    {
        _toastMessage = null;
        _toastTimer?.Dispose();
    }

    // ── Profile ──
    private async Task SaveProfile()
    {
        _saving = true;
        try
        {
            var updated = new UserProfile(_profileDisplayName, _profileEmail, _profileAvatarUrl, _profileBio);
            await SettingsService.SaveProfileAsync(updated);
            _savedProfile = updated;
            ShowToast("Profile saved successfully.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save profile: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    private void DiscardProfileChanges()
    {
        if (_savedProfile is not null)
        {
            _profileDisplayName = _savedProfile.DisplayName;
            _profileEmail = _savedProfile.Email;
            _profileAvatarUrl = _savedProfile.AvatarUrl;
            _profileBio = _savedProfile.Bio;
        }
    }

    // ── Notifications ──
    private void ToggleChannelMute(string channel, ChangeEventArgs e)
    {
        var isChecked = (bool)(e.Value ?? false);
        if (isChecked)
            _mutedChannels.Remove(channel);
        else if (!_mutedChannels.Contains(channel))
            _mutedChannels.Add(channel);
    }

    private async Task SaveNotifications()
    {
        _saving = true;
        try
        {
            var prefs = new NotificationPrefs(_notifEmail, _notifPush, _notifWeeklyDigest, new List<string>(_mutedChannels));
            await SettingsService.SaveNotificationPrefsAsync(prefs);
            ShowToast("Notification preferences saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save preferences: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Security ──
    private void TogglePasswordPanel() => _passwordPanelOpen = !_passwordPanelOpen;

    private async Task ChangePassword()
    {
        _passwordError = null;

        if (string.IsNullOrWhiteSpace(_currentPassword) || string.IsNullOrWhiteSpace(_newPassword))
        {
            _passwordError = "All password fields are required.";
            return;
        }
        if (_newPassword != _confirmPassword)
        {
            _passwordError = "New password and confirmation do not match.";
            return;
        }

        _saving = true;
        try
        {
            await SettingsService.ChangePasswordAsync(_currentPassword, _newPassword);
            _currentPassword = "";
            _newPassword = "";
            _confirmPassword = "";
            _passwordPanelOpen = false;
            _securityLastPasswordChange = DateTime.UtcNow;
            ShowToast("Password updated successfully.");
        }
        catch (Exception ex)
        {
            _passwordError = ex.Message;
        }
        finally
        {
            _saving = false;
        }
    }

    private void PromptRevokeSession(ActiveSession session) => _sessionToRevoke = session;
    private void CancelRevoke() => _sessionToRevoke = null;

    private async Task ConfirmRevokeSession()
    {
        if (_sessionToRevoke is null) return;
        _saving = true;
        try
        {
            await SettingsService.RevokeSessionAsync(_sessionToRevoke.Id);
            _sessions?.Remove(_sessionToRevoke);
            ShowToast($"Session on {_sessionToRevoke.Device} revoked.");
            _sessionToRevoke = null;
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to revoke session: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }

    // ── Appearance ──
    private string GetPreviewClasses()
    {
        var theme = _appearanceTheme switch
        {
            "Dark" => "preview-dark",
            "Light" => "preview-light",
            _ => "preview-system"
        };
        var font = _appearanceFontSize switch
        {
            "Small" => "preview-font-small",
            "Large" => "preview-font-large",
            _ => "preview-font-medium"
        };
        var compact = _appearanceCompactMode ? "preview-compact" : "";
        return $"{theme} {font} {compact}";
    }

    private async Task SaveAppearance()
    {
        _saving = true;
        try
        {
            var settings = new AppearanceSettings(_appearanceTheme, _appearanceFontSize, _appearanceLanguage, _appearanceCompactMode);
            await SettingsService.SaveAppearanceAsync(settings);
            ShowToast("Appearance settings saved.");
        }
        catch (Exception ex)
        {
            ShowToast($"Failed to save appearance: {ex.Message}", isError: true);
        }
        finally
        {
            _saving = false;
        }
    }
}
"}

