    border-radius: 8px;
    padding: 1.5rem 2rem;
    max-width: 420px;
    width: 90%;
    box-shadow: 0 8px 30px rgba(0, 0, 0, 0.2);
}

.confirm-dialog h5 {
    margin-bottom: 0.75rem;
}

/* ── Radio group ── */
.radio-group {
    display: flex;
    gap: 1.5rem;
    margin-top: 0.25rem;
}

.radio-item {
    display: flex;
    align-items: center;
    gap: 0.35rem;
    cursor: pointer;
}

/* ── Live preview ── */
.live-preview {
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 1.25rem;
    margin-top: 0.5rem;
    transition: all 0.25s;
}

.preview-header {
    font-weight: 600;
    margin-bottom: 0.5rem;
    padding-bottom: 0.5rem;
    border-bottom: 1px solid #dee2e6;
}

.preview-body {
    margin-bottom: 0.75rem;
}

.preview-button {
    padding: 0.35rem 1rem;
    border-radius: 4px;
    border: none;
    cursor: pointer;
    font-weight: 500;
}

/* Preview theme variations */
.preview-light {
    background: #fff;
    color: #212529;
}

.preview-light .preview-button {
    background: #0d6efd;
    color: #fff;
}

.preview-dark {
    background: #1e1e2e;
    color: #e0e0e0;
    border-color: #444;
}

.preview-dark .preview-header {
    border-color: #444;
}

.preview-dark .preview-button {
    background: #5b9aff;
    color: #1e1e2e;
}

.preview-system {
    background: #f0f4f8;
    color: #333;
}

.preview-system .preview-button {
    background: #0d6efd;
    color: #fff;
}

/* Preview font sizes */
.preview-font-small {
    font-size: 0.8rem;
}

.preview-font-medium {
    font-size: 1rem;
}

.preview-font-large {
    font-size: 1.2rem;
}

/* Preview compact */
.preview-compact {
    padding: 0.6rem;
    line-height: 1.3;
}

.preview-compact .preview-header {
    margin-bottom: 0.25rem;
    padding-bottom: 0.25rem;
}

.preview-compact .preview-body {
    margin-bottom: 0.35rem;
}

/* ── Toast ── */
.settings-toast {
    position: sticky;
    top: 0;
    z-index: 100;
    display: flex;
    justify-content: space-between;
    align-items: center;
    padding: 0.75rem 1rem;
    border-radius: 6px;
    margin-bottom: 1rem;
    font-weight: 500;
    animation: slideDown 0.25s ease;
}

.toast-success {
    background: #d1e7dd;
    color: #0a3622;
    border: 1px solid #badbcc;
}

.toast-error {
    background: #f8d7da;
    color: #58151c;
    border: 1px solid #f5c2c7;
}

.toast-dismiss {
    background: none;
    border: none;
    font-size: 1rem;
    cursor: pointer;
    color: inherit;
    padding: 0 0.25rem;
}

@keyframes slideDown {
    from { opacity: 0; transform: translateY(-8px); }
    to   { opacity: 1; transform: translateY(0); }
}
"}

